local function sST(tP) if not tP then return end sPl=tP SNL.Text=tP.DisplayName.." (@"..tP.Name..")" SAv.Image="rbxthumb://type=AvatarHeadShot&id="..tP.UserId.."&w=150&h=150" if tP.Character and tP.Character:FindFirstChild("Humanoid") then cam.CameraSubject=tP.Character.Humanoid end end
SSB.FocusLost:Connect(function() local tx=sL(SSB.Text) for _,pl in pairs(P:GetPlayers()) do if sF(sL(pl.Name),tx) or sF(sL(pl.DisplayName),tx) then sST(pl) break end end SSB.Text="" end)
