STB.MouseButton1Click:Connect(function() if sPl and sPl.Character and sPl.Character:FindFirstChild("HumanoidRootPart") then if p.Character and p.Character:FindFirstChild("HumanoidRootPart") then p.Character.HumanoidRootPart.CFrame=sPl.Character.HumanoidRootPart.CFrame end end end)
SSiB.MouseButton1Click:Connect(function() sE=not sE SSiB.Text=sE and "Sentar: ON" or "Sentar: OFF" SSiB.BackgroundColor3=sE and Color3.fromRGB(60,60,60) or Color3.fromRGB(28,28,28) if sCo then sCo:Disconnect() sCo=nil end if sE then sCo=RuS.Heartbeat:Connect(function() if sPl and sPl.Character and p.Character then local tH=sPl.Character:FindFirstChild("HumanoidRootPart") local mH=p.Character:FindFirstChild("HumanoidRootPart") local mHu=p.Character:FindFirstChild("Humanoid") if tH and mH and mHu then mHu.Sit=true mH.CFrame=tH.CFrame*CFrame.new(0,1.5,0) end end end) else local mHu=p.Character and p.Character:FindFirstChild("Humanoid") if mHu then mHu.Sit=false mHu.Jump=true end end end)
SStB.MouseButton1Click:Connect(function() sPl=nil SNL.Text="Ninguém selecionado" SAv.Image="" if p.Character and p.Character:FindFirstChild("Humanoid") then cam.CameraSubject=p.Character.Humanoid end if sE then sE=false SSiB.Text="Sentar: OFF" SSiB.BackgroundColor3=Color3.fromRGB(28,28,28) if sCo then sCo:Disconnect() sCo=nil end local mHu=p.Character and p.Character:FindFirstChild("Humanoid") if mHu then mHu.Sit=false mHu.Jump=true end end end)
local pO=true local pTS=UDim2.new(0,220,0,420) local function tP() pO=not pO if pO then MF.Size=UDim2.new(0,0,0,0) MF.Visible=true TwS:Create(MF,TweenInfo.new(0.4,Enum.EasingStyle.Quart,Enum.EasingDirection.Out),{Size=pTS}):Play() else local tw=TwS:Create(MF,TweenInfo.new(0.3,Enum.EasingStyle.Quart,Enum.EasingDirection.In),{Size=UDim2.new(0,0,0,0)}) tw:Play() task.spawn(function() tw.Completed:Wait() if not pO then MF.Visible=false end end) end end OB.MouseButton1Click:Connect(tP)
RB.MouseButton1Click:Connect(function() if #P:GetPlayers()<=1 then TS:Teleport(game.PlaceId,p) else TS:TeleportToPlaceInstance(game.PlaceId,game.JobId,p) end end)
tEn=false local function tT() tEn=not tEn TBn.Text=tEn and "CLICK TP: ON" or "CLICK TP ["..bK.Tp.Name.."]" TBn.BackgroundColor3=tEn and Color3.fromRGB(60,60,60) or Color3.fromRGB(28,28,28) end TBn.MouseButton1Click:Connect(tT) mo.Button1Down:Connect(function() if tEn and p.Character and p.Character:FindFirstChild("HumanoidRootPart") then p.Character.HumanoidRootPart.CFrame=CFrame.new(mo.Hit.Position+Vector3.new(0,3,0)) end end)
iSp=false local spC=nil local function tgSp() iSp=not iSp SB.Text=iSp and "SPAM OVO: ON" or "SPAM OVO ["..bK.Spam.Name.."]" SB.BackgroundColor3=iSp and Color3.fromRGB(60,60,60) or Color3.fromRGB(28,28,28) if iSp then spC=RuS.Heartbeat:Connect(function() local cF=workspace:FindFirstChild("Characters") local tg=cF and cF:FindFirstChild(p.Name) and cF[p.Name]:FindFirstChild("Storegg") if tg then pcall(function() rE:FireServer("TryStoregg",tg,mo.Hit.Position) end) end end) elseif spC then spC:Disconnect() spC=nil end end SB.MouseButton1Click:Connect(tgSp)
sCA=false local dPF=20 local function tSC() sCA=not sCA SCB.Text=sCA and "SPAM CAMERA: ON" or "SPAM CAMERA ["..bK.SpamCamera.Name.."]" SCB.BackgroundColor3=sCA and Color3.fromRGB(60,60,60) or Color3.fromRGB(28,28,28) end SCB.MouseButton1Click:Connect(tSC)
RuS.Heartbeat:Connect(function() if not sCA then return end local ch=workspace:FindFirstChild("Characters") and workspace.Characters:FindFirstChild(p.Name) local rm=ch and ch:FindFirstChild("Camera") and ch.Camera:FindFirstChild("Remote") if rm then for i=1,dPF do if not sCA then break end rm:FireServer() end end end)
local isF=false FB.MouseButton1Click:Connect(function() isF=not isF FB.Text=isF and "PEGAR OVOS: ON" or "PEGAR OVOS" FB.BackgroundColor3=isF and Color3.fromRGB(60,60,60) or Color3.fromRGB(28,28,28) if isF then task.spawn(function() while isF do local eg=workspace:FindFirstChild("Eggs") if p.Character and eg then for _,ob in pairs(eg:GetChildren()) do if not isF then break end if ob:IsA("Model") and sF(ob.Name,"Egg") then local tp=ob:FindFirstChildWhichIsA("BasePart",true) if tp then p.Character.HumanoidRootPart.CFrame=tp.CFrame*CFrame.new(0,8,0) task.wait(2.5) end end end end task.wait(1) end end) end end)
eEn=false local eF=Instance.new("Folder",SG) local function tgE() eEn=not eEn EB.Text=eEn and "ESP: ON" or "ESP ["..bK.Esp.Name.."]" EB.BackgroundColor3=eEn and Color3.fromRGB(60,60,60) or Color3.fromRGB(28,28,28) if not eEn then eF:ClearAllChildren() end end EB.MouseButton1Click:Connect(tgE)
task.spawn(function() while task.wait() do if eEn then for _,v in pairs(P:GetPlayers()) do if v~=p and v.Character and v.Character:FindFirstChild("Head") then local b=eF:FindFirstChild(v.Name) or Instance.new("BillboardGui",eF) b.Name=v.Name b.Adornee=v.Character.Head b.Size=UDim2.new(0,100,0,50) b.AlwaysOnTop=true local l=b:FindFirstChild("L") or Instance.new("TextLabel",b) l.Name="L" l.Size=UDim2.new(1,0,1,0) l.BackgroundTransparency=1 l.Font=Enum.Font.GothamBold l.TextSize=14 local r=v:GetRoleInGroup(G_ID) local d=mF((p.Character.HumanoidRootPart.Position-v.Character.HumanoidRootPart.Position).Magnitude) if A_R[r] then l.TextColor3=Color3.fromRGB(255,0,0) l.Text=v.Name.."\n["..r.."]\n"..d.."m" else l.TextColor3=Color3.fromRGB(255,255,255) l.Text=v.Name.."\n"..d.."m" end end end end end end)
UIS.InputBegan:Connect(function(i,pr) if pr then return end if i.KeyCode==Enum.KeyCode.G then tP() end if i.KeyCode==bK.Spam then tgSp() end if i.KeyCode==bK.SpamCamera then tSC() end if i.KeyCode==bK.Esp then tgE() end if i.KeyCode==bK.Tp then tT() end if i.KeyCode==bK.Fly then tF() end if i.KeyCode==bK.Speed then tS() end if i.KeyCode==bK.Noclip then tN() end end)
